class Solution {
    public int findKthNumber(int n, int k) {
        int cur = 1;
        k--;
        while (k > 0) {
            int steps = Math.min(k, n - cur + 1);
            k -= steps;
            n -= steps;
            cur += steps;
            if (k > 0 && cur < n) {
                cur++;
                k--;
            }
        }
        return cur;
    }
}
